<!-- @/components/layout/k2/K2Split.svelte -->
<script>
  import { onMount } from 'svelte';
  import { Splitpanes } from 'svelte-splitpanes';
  import { persist } from '$lib/stores/face-store.js';

  export let key = '';
  export let horizontal = false;
  export let defaultSizes = [];
  export let prefix = 'layout__';

  let paneSizes = [];

  // Key storage ổn định
  const storageKey = `${prefix}${key}`;

  // Dùng persist store thay vì localStorage raw
  const layoutStore = persist(storageKey, defaultSizes);

  // Subscribe store
  let unsubscribe;

  onMount(() => {
    unsubscribe = layoutStore.subscribe((value) => {
      if (Array.isArray(value) && value.length) {
        paneSizes = value;
      } else {
        paneSizes = defaultSizes;
      }
    });

    return () => {
      unsubscribe && unsubscribe();
    };
  });

  const handleResize = (event) => {
    const sizes = event?.detail;

    // Guard chống corrupt data (rất quan trọng)
    if (!Array.isArray(sizes)) return;

    const result = sizes.map((item) => {
      const safeSize = Number.isFinite(item?.size) ? Math.round(item.size) : (item?.size ?? 0);

      return {
        // Giữ nguyên config gốc (min, max, snap, locked...)
        ...item,

        // Chỉ normalize size
        size: safeSize

        // ❌ KHÔNG tự động override snapSize nữa (fix bug giật layout)
        // snapSize: undefined  <-- cố tình bỏ
      };
    });

    // Update store (persist tự sync localStorage)
    layoutStore.set(result);
  };
</script>

<Splitpanes {horizontal} on:resize={handleResize} {...$$restProps}>
  <slot {paneSizes} />
</Splitpanes>
